		items = {
			[1] = { str = "1. 40-41 Badlands" },
			[2] = { str = "2. Идите в точку 53,43 берите задание  #ACCEPT“Fiery Blaze Enchantment”#,  #ACCEPT“Mirages”#,  и  #ACCEPT“A Dwarf and His Tools”#", x = 53, y = 43, zone = "Badlands" },
			[3] = { str = "3. Дойдите до точки 42,52 и сдайте задание  #TURNIN“Martek the Exiled”#  берите следующее  #ACCEPT“Indurium”#", x = 45, y = 52, zone = "Badlands" },
			[4] = { str = "4. Возьмите задание  #ACCEPT“Barbecued Buzzard Wings”#  и  #ACCEPT“Pearl Diving”# (если вы купили ранее на аукционе жемчужины для задания) и сразу сдайте это задание." },
			[5] = { str = "5. Стервятники нужны для выполнения 2х заданий. Паком обитают в точке 16,60 у каргата так что убивайте их всякий раз когда увидите на своем пути." },
			[6] = { str = "6. Идите по координатам 25,44 возьмите задание  #ACCEPT“Study of the Elements: Rock pt.1”#  и  #ACCEPT“Coolant Heads Prevail”#,  задание сдайте  #TURNIN“Coolant Heads Prevail”#  берите следующее  #ACCEPT“Gyro… What?”#  затем сдайте и его (если купили предмет на аукционе).", x = 25, y = 44, zone = "Badlands" },
			[7] = { str = "7. НПС это задание может вам не сразу задание может появиться после выполнения некоторых заданий в этой локации  #ACCEPT“Liquid Stone”#  если есть нужные банки в инвентаре сдайте его обратно." },
			[8] = { str = "8. #HUNTERЗадание для охотников. Идите в точку 20,53 и приручите Ridge Stalker Patriarch и выучите способность питомца dash и prowl 2го ранга.#", x = 20, y = 53, zone = "Badlands"},
			[9] = { str = "9. Задание для охотников. Жмите #PICTUREHearth# в Thelsamar, #HUNTERзаберите кота обратно, НЕ ОТПУСКАЙТЕ ПЕТА идите обратно с катом в badlands#"},
			[10] = { str = "10. Убивайте мобов пока идете в точку 66,21 там откройте ящик для задания  #DOQUEST“Mirages”#", x = 66, y = 21, zone = "Badlands" },
			[11] = { str = "11. Идите к месту раскопок в точку 53,29 и убивайте дворфов для задания  #DOQUEST“A Dwarf and His Tools”#  Справа от ямы в точке 53,33 коснитесь записки в палатке что бы получить задание  #DOQUEST“A Sign of Hope”#", x = 53, y = 29, zone = "Badlands" },
			[12] = { str = "12. Гриндите мобов до точки 53,43 и сдайте задание  #TURNIN“Mirages”#  берите следующее  #ACCEPT“Scrounging”#", x = 53, y = 43, zone = "Badlands" },
			[13] = { str = "13. Так же сдайте задания  #TURNIN“A Dwarf and His Tools”#  и  #TURNIN“A Sign of Hope”#  берите следующую часть в Uldaman'e" },
			[14] = { str = "14. Гриндите мобов до точки 61,54 и возьмите задание  #ACCEPT“Tremors of the Earth”#  огры ходят от точки 62,70  до точки 29,56 босса убить легко либо выманить его с малым количеством охраны.", x = 61, y = 54, zone = "Badlands" },
			[15] = { str = "15. Идите на юг в точку 62,70 и убивайте огров для задания  #DOQUEST“Scrounging”#  тут может появиться босс из предыдущего задания.", x = 62, y = 70, zone = "Badlands" },
			[16] = { str = "16. Гриндите до точки 50,62, сдайте задание  #TURNIN“Find Agmond”#  и возьмите следующее  #ACCEPT“Murdaloc”#", x = 50, y = 62, zone = "Badlands" },
			[17] = { str = "17. Отправляйтесь немного южнее в лагерь гноллов и выполните задание  #DOQUEST“Murdaloc”#  и  #DOQUEST“Indurium”#" },
			[18] = { str = "18. Идите в точку 42,52 и сдайте задание  #TURNIN“Barbecued Buzzard Wings”#  и  #TURNIN“Indurium”#  берите следующее  #ACCEPT“News for Fizzle”#", x = 45, y = 52, zone = "Badlands" },
			[19] = { str = "19. Идите в точку 18,41 и убивайте lesser rock elementals для задания  #DOQUEST“Study of the Elements: Rock pt.1”#  и  #DOQUEST“Badlands Reagent Run”#", x = 18, y = 41, zone = "Badlands" },
