			[21] = { str = "21. Вернитесь в точку 26,44 и сдайте задание  #TURNIN“Study of the Elements: Rock pt.2”#  берите следующее  #ACCEPT“Study of the Elements: Rock pt.3”#", x = 26, y = 44, zone = "Badlands" },
			[22] = { str = "22. Убивайте Стервятников в точке 15,60 и Койотов в токе 33,62 для задания  #DOQUEST“Badlands Reagent Run”# если они вам еще нужны", x = 33, y = 62, zone = "Badlands" },
			[23] = { str = "23. Гриндите до точки 11,77 и убивайте огров для задания  #DOQUEST“Scrounging”#", x = 11, y = 77, zone = "Badlands" },
			[24] = { str = "24. Убивайте greater rock elementals в точке 14,88 для задлания  #DOQUEST“Study of the Elements: Rock#", x = 14, y = 88, zone = "Badlands" },
			[25] = { str = "25. Идите назад в точку 26,44 сдайте задание  #TURNIN“Study of the Elements: Rock pt.3”#  возьмите следующее  #ACCEPT“This Is Going To Be Hard pt.1”#  повернитесь и сдайте его, возьмите следующее задание  #ACCEPT“This Is Going To Be Hard pt.2”#  повернитесь и снова сдайте его, возьмите следующее задание  #ACCEPT“This Is Going To Be Hard pt.3”#", x = 26, y = 44, zone = "Badlands" },
			[26] = { str = "26. Убейте призванного элементаля он 45 уровня. Затем сдайте его и получите свой Nifty Stopwatch" },
			[27] = { str = "27. Идите в точку 53,43 и сдайте  #TURNIN“Scrounging”#", x = 53, y = 43, zone = "Badlands" },
			[28] = { str = "28. Идите в точку 61,54 и сдайте заадние  #TURNIN“Tremors of the Earth”# следующее задание ПРОПУСТИТЕ", x = 61, y = 54, zone = "Badlands" },
			[29] = { str = "29. Сейчас у вас должен быть 41 уровень, если вы не получили 41 уровень идите на восток и гриндите детенышей драконов the whelps. Если вы получили 41 уровень на велпах то желательно еще погриндить их тут минут 30 что был запас по опыту если вы не выбили с них heart для задания  #DOQUEST“Fiery Blaze Enchantment”#  за это время то бросьте это задание." },
			[30] = { str = "30. Жмите Hearth в Thelsamar" },
			[31] = { str = "31. Идите в дом за гостиницей и сдайте задание  #TURNIN“Badlands Reagent Run”#  берите часть заданий относящиеся к Uldaman" },
			[32] = { str = "32. Бегите в точку 65,65 и сдайте задание  #TURNIN“Murdaloc”#  берите еще задание Uldaman. Сейчас я уже заполнил полоску опыта на 25% до 41 уровня", x = 65, y = 65, zone = "Loch Modan" },
			[33] = { str = "33. #PICTUREЛетите в Duskwood#"},
			[34] = { str = "34. #PICTUREОстановитесь тут в гостинице#."}, 
			[35] = { str = "35. #PICTUREЛетите в SW# и идите в точку 64,20 и возьмите задание  #ACCEPT“In Search of The Temple”#", x = 64, y = 20, zone = "Stormwind" },
			[36] = { str = "36. #PICTUREЛетите назад в Duskwood#, Бегите в Swamp of Sorrows" },
		}
