			[13] = { str = "13. Идите в точку 26,59 и сдайте задание  #TURNIN“The Lost Caravan”#  берите следующее задание  #ACCEPT“Driftwood”#", x = 26, y = 59, zone = "Swamp of Sorrows" },
			[14] = { str = "14. Направляйся на юг в Blasted Lands в точку 36,59 к крепости Nethergarde Keep в точку 54,78. Откройте полетчика и летите Darkshire.", x = 54, y = 78, zone = "Blasted Lands" },
			[15] = { str = "15. #HUNTERОставьте кошку в стойле и возьмите другую из Badlands.#" },
			[16] = { str = "16. Возьмите задание  #ACCEPT“Supplies for Nethergarde”# по пути обратно на северо-восток" },
			[17] = { str = "17. #PICTUREЛетите в крепость Nethergarde#, и сдайте задание  #TURNIN“Supplies for Nethergarde”#." },
			[18] = { str = "18. Вернитесь обратно в Swamp of Sorrows." },
			[19] = { str = "19. Бегите к озеру вогруг подземелья Sunken Temple в точке 70,54 и разведайте территорию для задания  #DOQUESTIn Search of The Temple#", x = 70, y = 54, zone = "Swamp of Sorrows" },
			[20] = { str = "20. Идите в точку 76,6 и начинайте убивать crawlers и work для задания  #DOQUEST“… and bugs”# until it’s пока не выполните задание. Ищите деревянные доски на земле для задания  #DOQUEST“Driftwood”#", x = 76, y = 6, zone = "Swamp of Sorrows" },
			[21] = { str = "21. #HUNTERКогда вы выполните предыдущие 2 задания отпустите кошку и приручите silt crawler 40-41 уровня что бы выучить способность claw 6 ранга.#" },
			[22] = { str = "22. Жмите #PICTUREHearth# в Darkshire #HUNTERЗаберите свою кошку обратно из стойла.#" },
			[23] = { str = "23. Летите в Nethergarde и бегите назад в Swamp of Sorrows." },
			[24] = { str = "24. Идите в точку 26,59 и сдайте задание  #TURNIN“Driftwood”#  берите следующее  #ACCEPT“Deliver the Shipment”#.", x = 26, y = 59, zone = "Swamp of Sorrows" },
			[25] = { str = "25. Идите в Blasted Lands и сдайте задание  #TURNIN“Deliver the Shipment”#  в точке 66,21.", x = 66, y = 21, zone = "Blasted Lands" },
			[26] = { str = "25. Летите в Booty Bay и сдайте задание  #TURNIN“Dream Dust In the Swamp”#  возьмите новое задание  #ACCEPT“Rumors for Kravel”#." },
			[27] = { str = "27. Садитесь на корабль до Rachet и летите в Theramore и сдайте задание  #TURNIN“… and bugs”#  в гостинице." },
