			[8] = { str = "8. Выходите из BB и поворачивайте направо и на юг в точке 31,79 и убивайте пиратов для заданий  #DOQUEST“Up To Snuff”#  и  #DOQUEST“Keep An Eye Out”#", x = 31, y = 79, zone = "Stranglethorn Vale" },
